    int integerReplacement(int n) {
        int res = 0;
        while (n > 1) {
            if ((n & 1) == 1) {
                if (n == 3 || (n & 2) == 2) n--;
                else n++;
            }
            n >>= 1;
            res++;
        }
        return res;
    }
};```
